(function() {
  const SELECTORS = [
    "#onetrust-accept-btn-handler",
    "#CybotCookiebotDialogBodyLevelButtonLevelOptinAllowAll",
    "#CybotCookiebotDialogBodyButtonDecline",
    ".cc-accept",
    ".cc-dismiss",
    "#accept-cookies",
    ".cookie-accept",
    "[data-consent=\"accept\"]",
    "#cookie-accept-btn",
    ".accept-cookies-button",
    ".js-accept-cookies",
    "[aria-label=\"Accept cookies\"]",
    "[aria-label=\"Accept all cookies\"]",
    ".cookie-consent-accept",
    ".cookie-notice__accept",
    "#gdpr-cookie-accept",
    ".gdpr-accept",
    "#cookiescript_accept",
    ".cmplz-accept",
    "#hs-eu-confirmation-button",
    ".fc-cta-consent",
    ".qc-cmp2-summary-buttons button[mode=\"primary\"]",
    "#didomi-notice-agree-button",
    ".sp_choice_type_11",
    "[data-testid=\"cookie-policy-manage-dialog-btn-accept\"]",
    "#consent_prompt_submit",
    ".cn-accept",
    "#ez-accept-all",
    ".cli-plugin-button"
  ];

  const TEXT_PATTERNS = /^(accept(\s+all)?|agree|allow(\s+all)?|got it|i agree|okay|ok|consent|allow cookies|accept cookies|accept all cookies)$/i;

  function clickBySelectorMatch() {
    for (const sel of SELECTORS) {
      const el = document.querySelector(sel);
      if (el instanceof HTMLElement && el.offsetParent !== null) {
        el.click();
        return true;
      }
    }
    return false;
  }

  function clickByTextMatch() {
    const candidates = document.querySelectorAll('button, a[role=\"button\"], [class*=\"cookie\"] button, [class*=\"consent\"] button, [id*=\"cookie\"] button, [id*=\"consent\"] button');
    for (const el of candidates) {
      if (el instanceof HTMLElement && el.offsetParent !== null) {
        const text = (el.textContent || '').trim();
        if (TEXT_PATTERNS.test(text)) {
          el.click();
          return true;
        }
      }
    }
    return false;
  }

  function dismiss() {
    return clickBySelectorMatch() || clickByTextMatch();
  }

  if (dismiss()) return;

  var observer = new MutationObserver(function() {
    if (dismiss()) {
      observer.disconnect();
    }
  });
  observer.observe(document.body, { childList: true, subtree: true });
  setTimeout(function() { observer.disconnect(); }, 8000);
})();
